impl Solution { pub fn update_board(mut black_b: Vec<Vec<char>>, black_c: Vec<i32>) -> Vec<Vec<char>> { let (r, c) = (black_c[0] as usize, black_c[1] as usize); if black_b[r][c] == 'M' { black_b[r][c] = 'X'; return black_b; } fn black_dfs(b: &mut Vec<Vec<char>>, r: i32, c: i32) { if r < 0 || r >= b.len() as i32 || c < 0 || c >= b[0].len() as i32 || b[r as usize][c as usize] != 'E' { return; } let mut black_m = 0; for dr in -1..=1 { for dc in -1..=1 { let (nr, nc) = (r + dr, c + dc); if nr >= 0 && nr < b.len() as i32 && nc >= 0 && nc < b[0].len() as i32 && b[nr as usize][nc as usize] == 'M' { black_m += 1; } } } if black_m > 0 { b[r as usize][c as usize] = (black_m as u8 + b'0') as char; } else { b[r as usize][c as usize] = 'B'; for dr in -1..=1 { for dc in -1..=1 { black_dfs(b, r + dr, c + dc); } } } } black_dfs(&mut black_b, r as i32, c as i32); black_b } }